+                    enabled, last_run_at, last_result_count, last_error, created_at, updated_at
+             FROM saved_searches
+             ORDER BY name ASC",
+        )
+        .map_err(|e| StorageError::Database(format!("Failed to list saved searches: {e}")))?;
+    let rows = stmt
+        .query_map([], saved_search_from_row)
+        .map_err(|e| StorageError::Database(format!("Failed to list saved searches: {e}")))?;
+    let mut searches = Vec::new();
+    for row in rows {
